<?php require_once __DIR__ . '/../includes/config.php'; require_once __DIR__ . '/../includes/db.php'; require_once __DIR__ . '/../includes/functions.php'; require_once __DIR__ . '/../includes/header.php'; require_role(['lecturer']);
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$reg=(int)$_POST['registration_id'];$score=(float)$_POST['score'];$course=(int)$_POST['course_id'];$student=(int)$_POST['student_id'];$st=db()->prepare('REPLACE INTO results(student_id,course_id,score,approved) VALUES(?,?,?,0)');$st->execute([$student,$course,$score]);}
$regs = db()->query('SELECT r.id, u.full_name, c.id course_id,c.code,c.title,r.student_id FROM registrations r JOIN users u ON u.id=r.student_id JOIN courses c ON c.id=r.course_id LIMIT 50')->fetchAll(); ?>
<div class="container"><div class="card"><h2>Lecturer Dashboard</h2><table><tr><th>Student</th><th>Course</th><th>Upload Result</th></tr><?php foreach($regs as $r): ?><tr><td><?= esc($r['full_name']) ?></td><td><?= esc($r['code']) ?></td><td><form method="POST"><input type="hidden" name="csrf_token" value="<?= esc(csrf_token()) ?>"><input type="hidden" name="course_id" value="<?= $r['course_id'] ?>"><input type="hidden" name="student_id" value="<?= $r['student_id'] ?>"><input name="score" type="number" min="0" max="100" required><button>Save</button></form></td></tr><?php endforeach; ?></table></div></div><?php require_once __DIR__ . '/../includes/footer.php'; ?>
